Iteratively attempt to insert each ship into existing non-empty assigns ordered by increasing current route cost, then try empty assigns; if still failing, create a new assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	type idxCost struct {
		idx  int
		cost float64
	}
	for _, oi := range orderIndices {
		inserted := false
		var candidates []idxCost
		for i := 0; i < dispatch.AssignsLen; i++ {
			candidates = append(candidates, idxCost{i, dispatch.Assigns[i].Cost})
		}
		sort.SliceStable(candidates, func(a, b int) bool {
			return candidates[a].cost < candidates[b].cost
		})
		for _, c := range candidates {
			ok := dispatch.Assigns[c.idx].AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				dispatch.Assigns[c.idx].GenRoute()
				if dispatch.Assigns[c.idx].Cost >= 0 {
					inserted = true
					break
				}
				dispatch.Assigns[c.idx].RemoveShip(total_ship + oi)
				dispatch.Assigns[c.idx].GenRoute()
			}
		}
		if !inserted {
			for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
				ok := dispatch.Assigns[i].AddShip(total_ship+oi, oris[oi], dess[oi])
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						dispatch.AssignsLen = i + 1
						inserted = true
						break
					}
					dispatch.Assigns[i].RemoveShip(total_ship + oi)
					dispatch.Assigns[i].GenRoute()
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				i := dispatch.AssignsLen
				dispatch.Assigns[i].AddShip(total_ship+oi, oris[oi], dess[oi])
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[i].RemoveShip(total_ship + oi)
					dispatch.Assigns[i].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

